.darma-loader-loading-io-06 {
      position: relative;
      display: inline-block;
      width: 52px;
      height: 52px;
      border-radius: 50%;
      border: 1px solid color-mix(in srgb, var(--loader-color, #14b8a6) 24%, transparent);
    }
    .darma-loader-loading-io-06 i {
      position: absolute;
      inset: -3px;
      border-radius: 50%;
      animation: darma-loader-loading-io-06-orbit 1.2s linear infinite;
    }
    .darma-loader-loading-io-06 i::before {
      content: "";
      position: absolute;
      top: 0;
      left: 50%;
      width: 10px;
      height: 10px;
      margin-left: -5px;
      border-radius: 50%;
      background: var(--loader-color, #14b8a6);
      box-shadow: 0 0 18px color-mix(in srgb, var(--loader-color, #14b8a6) 45%, transparent);
    }
    .darma-loader-loading-io-06 i:nth-child(1) { animation-delay: 0.00s; }
.darma-loader-loading-io-06 i:nth-child(2) { animation-delay: -0.60s; }
    @keyframes darma-loader-loading-io-06-orbit { to { transform: rotate(360deg); } }

